class SecureDataHandler:
    """Handles HMAC signing and verification for sensitive data stored in Redis."""

    def __init__(self, secret_key: str):
        if not secret_key:
            logger.warning(
                "ENCRYPTION_KEY not set. Using a generated key. "
                "This is NOT suitable for production or multi-instance deployments."
            )
            secret_key = secrets.token_hex(32)
        self._secret_key = secret_key.encode('utf-8')

    def sign_data(self, data: str) -> str:
        """Create an HMAC signature for the data and prepend it."""
        signature = hmac.new(self._secret_key, data.encode('utf-8'), hashlib.sha256).hexdigest()
        return f"{signature}:{data}"

    def verify_and_extract(self, signed_data: str) -> Optional[str]:
        """Verify the HMAC signature and return the original data if valid."""
        if not signed_data or ':' not in signed_data:
            return None
        signature, data = signed_data.split(':', 1)
        expected_signature = hmac.new(self._secret_key, data.encode('utf-8'), hashlib.sha256).hexdigest()
        if hmac.compare_digest(signature, expected_signature):
            return data
        logger.warning("HMAC signature verification failed - possible data tampering")
        return None


class RedisClusterManager:
    """Manages connections to a Redis cluster with retry logic and health checks."""

    def __init__(self):
        self._cluster: Optional[RedisCluster] = None
        self._secure_handler = SecureDataHandler(ENCRYPTION_KEY)
        self._connect()

    def _parse_nodes(self):
        """Parse Redis node addresses from configuration."""
        nodes = []
        for node_str in REDIS_NODES.split(","):
            node_str = node_str.strip()
            if ":" in node_str:
                host, port = node_str.rsplit(":", 1)
                nodes.append(ClusterNode(host=host, port=int(port)))
            else:
                nodes.append(ClusterNode(host=node_str, port=6379))
        return nodes

    def _connect(self):
        """Establish connection to the Redis cluster."""
        nodes = self._parse_nodes()
        retry_count = 0
        max_retries = 5

        while retry_count < max_retries:
            try:
                self._cluster = RedisCluster(
                    startup_nodes=nodes,
                    password=REDIS_PASSWORD if REDIS_PASSWORD else None,
                    ssl=REDIS_SSL,
                    ssl_cert_reqs="required" if REDIS_SSL else None,
                    max_connections=REDIS_MAX_CONNECTIONS,
                    socket_timeout=REDIS_SOCKET_TIMEOUT,
                    socket_connect_timeout=REDIS_SOCKET_TIMEOUT,
                    retry_on_timeout=REDIS_RETRY_ON_TIMEOUT,
                    decode_responses=True,
                    skip_full_coverage_check=True,
                )
                # Test connection
                self._cluster.ping()
                logger.info("Successfully connected to Redis cluster")
                return
            except (ConnectionError, TimeoutError, RedisError) as e:
                retry_count += 1
                wait_time = min(2 ** retry_count, 30)
                logger.error(
                    f"Failed to connect to Redis cluster (attempt {retry_count}/{max_retries}): {e}"
                )
                if retry_count < max_retries:
                    logger.info(f"Retrying in {wait_time} seconds...")
                    time.sleep(wait_time)
                else:
                    logger.critical("Could not connect to Redis cluster after max retries")
                    raise

    def _ensure_connection(self):
        """Ensure the Redis cluster connection is alive; reconnect if needed."""
        try:
            if self._cluster:
                self._cluster.ping()
        except (ConnectionError, TimeoutError, RedisError):
            logger.warning("Redis connection lost. Attempting to reconnect...")
            self._connect()

    @property
    def client(self) -> RedisCluster:
        self._ensure_connection()
        return self._cluster

    @property
    def secure_handler(self) -> SecureDataHandler:
        return self._secure_handler

    def health_check(self) -> Dict[str, Any]:
        """Perform a health check on the Redis cluster."""
        try:
            start = time.time()
            self.client.ping()
            latency = (time.time() - start) * 1000

            cluster_info = self.client.cluster_info()

            return {
                "status": "healthy",
                "latency_ms": round(latency, 2),
                "cluster_state": cluster_info.get("cluster_state", "unknown"),
                "cluster_slots_assigned": cluster_info.get("cluster_slots_assigned", 0),
                "cluster_slots_ok": cluster_info.get("cluster_slots_ok", 0),
                "cluster_known_nodes": cluster_info.get("cluster_known_nodes", 0),
                "cluster_size": cluster_info.get("cluster_size", 0),
            }
        except Exception as e:
            return {
                "status": "unhealthy",
                "error": str(e),
            }


class SessionManager:
    """Manages user session tokens in Redis."""

    def __init__(self, redis_manager: RedisClusterManager):
        self._redis = redis_manager
        self._secure = redis_manager.secure_handler

    def create_session(self, user_id: str, metadata: Optional[Dict] = None) -> str:
        """Create a new session token for a user and store it in Redis."""
        session_token = secrets.token_urlsafe(48)
        session_data = {
            "user_id": user_id,
            "created_at": datetime.utcnow().isoformat(),
            "metadata": metadata or {},
        }
        serialized = json.dumps(session_data)
        signed_data = self._secure.sign_data(serialized)

        key = f"{KEY_PREFIX_SESSION}{session_token}"
        self._redis.client.setex(key, SESSION_TOKEN_TTL, signed_data)

        # Also maintain a user-to-sessions index for session management
        user_sessions_key = f"user_sessions:{user_id}"
        self._redis.client.sadd(user_sessions_key, session_token)
        self._redis.client.expire(user_sessions_key, SESSION_TOKEN_TTL)

        logger.info(f"Session created for user {user_id}")
        return session_token

    def validate_session(self, session_token: str) -> Optional[Dict]:
        """Validate a session token and return session data if valid."""
        key = f"{KEY_PREFIX_SESSION}{session_token}"
        signed_data = self._redis.client.get(key)

        if not signed_data:
            return None

        data = self._secure.verify_and_extract(signed_data)
        if not data:
            logger.warning(f"Session token integrity check failed for key {key}")
            self._redis.client.delete(key)
            return None

        session_data = json.loads(data)

        # Check if session is blacklisted
        blacklist_key = f"{KEY_PREFIX_BLACKLIST}{session_token}"
        if self._redis.client.exists(blacklist_key):
            logger.warning(f"Blacklisted session token used: {session_token[:8]}...")
            return None

        return session_data

    def refresh_session(self, session_token: str) -> bool:
        """Refresh the TTL of an existing session."""
        key = f"{KEY_PREFIX_SESSION}{session_token}"
        if self._redis.client.exists(key):
            self._redis.client.expire(key, SESSION_TOKEN_TTL)
            return True
        return False

    def revoke_session(self, session_token: str) -> bool:
        """Revoke a session token."""
        key = f"{KEY_PREFIX_SESSION}{session_token}"
        signed_data = self._redis.client.get(key)

        if signed_data:
            data = self._secure.verify_and_extract(signed_data)
            if data:
                session_data = json.loads(data)
                user_id = session_data.get("user_id")
                if user_id:
                    user_sessions_key = f"user_sessions:{user_id}"
                    self._redis.client.srem(user_sessions_key, session_token)

        # Blacklist the token for the remaining TTL period
        ttl = self._redis.client.ttl(key)
        if ttl and ttl > 0:
            blacklist_key = f"{KEY_PREFIX_BLACKLIST}{session_token}"
            self._redis.client.setex(blacklist_key, ttl, "revoked")

        deleted = self._redis.client.delete(key)
        if deleted:
            logger.info(f"Session revoked: {session_token[:8]}...")
        return bool(deleted)

    def revoke_all_user_sessions(self, user_id: str) -> int:
        """Revoke all sessions for a specific user."""
        user_sessions_key = f"user_sessions:{user_id}"
        session_tokens = self._redis.client.smembers(user_sessions_key)

        count = 0
        for token in session_tokens:
            if self.revoke_session(token):
                count += 1

        self._redis.client.delete(user_sessions_key)
        logger.info(f"Revoked {count} sessions for user {user_id}")
        return count


class APIKeyManager:
    """Manages API keys in Redis."""

    def __init__(self, redis_manager: RedisClusterManager):
        self._redis = redis_manager
        self._secure = redis_manager.secure_handler

    def store_api_key(self, user_id: str, key_name: str, permissions: Optional[list] = None,
                      ttl: Optional[int] = None) -> str:
        """Generate and store a new API key for a user."""
        api_key = f"sk_{secrets.token_urlsafe(40)}"
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()

        key_data = {
            "user_id": user_id,
            "key_name": key_name,
            "permissions": permissions or ["read"],
            "created_at": datetime.utcnow().isoformat(),
            "key_prefix": api_key[:8],
        }

        serialized = json.dumps(key_data)
        signed_data = self._secure.sign_data(serialized)

        effective_ttl = ttl or API_KEY_TTL
        redis_key = f"{KEY_PREFIX_API_KEY}{key_hash}"
        self._redis.client.setex(redis_key, effective_ttl, signed_data)

        # Index: user -> api keys
        user_keys_index = f"user_api_keys:{user_id}"
        self._redis.client.sadd(user_keys_index, key_hash)
        self._redis.client.expire(user_keys_index, effective_ttl)

        logger.info(f"API key '{key_name}' created for user {user_id}")
        return api_key

    def validate_api_key(self, api_key: str) -> Optional[Dict]:
        """Validate an API key and return associated data."""
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        redis_key = f"{KEY_PREFIX_API_KEY}{key_hash}"

        signed_data = self._redis.client.get(redis_key)
        if not signed_data:
            return None

        data = self._secure.verify_and_extract(signed_data)
        if not data:
            logger.warning(f"API key integrity check failed for hash {key_hash[:8]}...")
            self._redis.client.delete(redis_key)
            return None

        return json.loads(data)

    def revoke_api_key(self, api_key: str) -> bool:
        """Revoke an API key."""
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        redis_key = f"{KEY_PREFIX_API_KEY}{key_hash}"

        signed_data = self._redis.client.get(redis_key)
        if signed_data:
            data = self._secure.verify_and_extract(signed_data)
            if data:
                key_data = json.loads(data)
                user_id = key_data.get("user_id")
                if user_id:
                    user_keys_index = f"user_api_keys:{user_id}"
                    self._redis.client.srem(user_keys_index, key_hash)

        deleted = self._redis.client.delete(redis_key)
        if deleted:
            logger.info(f"API key revoked: {key_hash[:8]}...")
        return bool(deleted)

    def list_user_api_keys(self, user_id: str) -> list:
        """List all API key metadata for a user (without the actual keys)."""
        user_keys_index = f"user_api_keys:{user_id}"
        key_hashes = self._redis.client.smembers(user_keys_index)

        keys_info = []
        for key_hash in key_hashes:
            redis_key = f"{KEY_PREFIX_API_KEY}{key_hash}"
            signed_data = self._redis.client.get(redis_key)
            if signed_data:
                data = self._secure.verify_and_extract(signed_data)
                if data:
                    key_data = json.loads(data)
                    keys_info.append({
                        "key_name": key_data.get("key_name"),
                        "key_prefix": key_data.get("key_prefix"),
                        "permissions": key_data.get("permissions"),
                        "created_at": key_data.get("created_at"),
                    })
            else:
                # Clean up stale index entries
                self._redis.client.srem(user_keys_index, key_hash)

        return keys_info


class UserProfileCache:
    """Caches user profile data in Redis."""

    def __init__(self, redis_manager: RedisClusterManager):
        self._redis = redis_manager

    def cache_profile(self, user_id: str, profile_data: Dict) -> None:
        """Cache user profile data."""
        # Remove any truly sensitive fields before caching
        safe_data = {k: v for k, v in profile_data.items()
                     if k not in ("password", "password_hash", "ssn", "credit_card")}
        key = f"{KEY_PREFIX_USER_PROFILE}{user_id}"
        self._redis.client.setex(key, USER_PROFILE_CACHE_TTL, json.dumps(safe_data))

    def get_profile(self, user_id: str) -> Optional[Dict]:
        """Get cached user profile data."""
        key = f"{KEY_PREFIX_USER_PROFILE}{user_id}"
        data = self._redis.client.get(key)
        if data:
            return json.loads(data)
        return None

    def invalidate_profile(self, user_id: str) -> bool:
        """Invalidate cached user profile."""
        key = f"{KEY_PREFIX_USER_PROFILE}{user_id}"
        return bool(self._redis.client.delete(key))


class RateLimiter:
    """Implements sliding window rate limiting using Redis."""

    def __init__(self, redis_manager: RedisClusterManager):
        self._redis = redis_manager

    def is_rate_limited(self, identifier: str, max_requests: Optional[int] = None,
                        window: Optional[int] = None) -> Dict[str, Any]:
        """Check if the identifier is rate limited using a sliding window."""
        max_req = max_requests or RATE_LIMIT_MAX_REQUESTS
        win = window or RATE_LIMIT_WINDOW

        key = f"{KEY_PREFIX_RATE_LIMIT}{identifier}"
        now = time.time()
        window_start = now - win

        pipe = self._redis.client.pipeline()
        # Remove entries outside the window
        pipe.zremrangebyscore(key, 0, window_start)
        # Add current request
        pipe.zadd(key, {f"{now}:{secrets.token_hex(4)}": now})
        # Count requests in window
        pipe.zcard(key)
        # Set expiry on the key
        pipe.expire(key, win)
        results = pipe.execute()

        request_count = results[2]
        is_limited = request_count > max_req

        return {
            "is_limited": is_limited,
            "current_requests": request_count,
            "max_requests": max_req,
            "window_seconds": win,
            "remaining": max(0, max_req - request_count),
        }


