def get_managers():
    """Lazy initialization of managers."""
    global redis_manager, session_manager, api_key_manager, profile_cache, rate_limiter
    if redis_manager is None:
        redis_manager = RedisClusterManager()
        session_manager = SessionManager(redis_manager)
        api_key_manager = APIKeyManager(redis_manager)
        profile_cache = UserProfileCache(redis_manager)
        rate_limiter = RateLimiter(redis_manager)
    return redis_manager, session_manager, api_key_manager, profile_cache, rate_limiter


def require_service_auth(f):
    """Decorator to require service-level authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("X-Service-API-Key", "")
        if not SERVICE_API_KEY:
            logger.warning("SERVICE_API_KEY not configured - skipping service auth")
        elif not hmac.compare_digest(auth_header, SERVICE_API_KEY):
            return jsonify({"error": "Unauthorized - invalid service API key"}), 401
        return f(*args, **kwargs)
    return decorated


def require_session(f):
    """Decorator to require a valid session token."""
    @wraps(f)
    def decorated(*args, **kwargs):
        _, sm, _, _, _ = get_managers()
        token = request.headers.get("Authorization", "").replace("Bearer ", "")
        if not token:
            return jsonify({"error": "Missing session token"}), 401

        session_data = sm.validate_session(token)
        if not session_data:
            return jsonify({"error": "Invalid or expired session"}), 401

        g.session_data = session_data
        g.session_token = token
        return f(*args, **kwargs)
    return decorated


def apply_rate_limit(f):
    """Decorator to apply rate limiting."""
    @wraps(f)
    def decorated(*args, **kwargs):
        _, _, _, _, rl = get_managers()
        identifier = request.headers.get("X-Forwarded-For", request.remote_addr)
        result = rl.is_rate_limited(identifier)

        if result["is_limited"]:
            response = jsonify({
                "error": "Rate limit exceeded",
                "retry_after": result["window_seconds"],
            })
            response.status_code = 429
            response.headers["Retry-After"] = str(result["window_seconds"])
            response.headers["X-RateLimit-Limit"] = str(result["max_requests"])
            response.headers["X-RateLimit-Remaining"] = "0"
            return response

        resp = f(*args, **kwargs)
        if hasattr(resp, 'headers'):
            resp.headers["X-RateLimit-Limit"] = str(result["max_requests"])
            resp.headers["X-RateLimit-Remaining"] = str(result["remaining"])
        return resp
    return decorated


